{
  "decisions": [
    {
      "id": "D1",
      "content": "プロジェクト・アオゾラを本日付で正式キックオフし、正式発足とする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D2",
      "content": "週次定例は毎週水曜日10:00から1時間で開催し、各部署から1名参加のうえリモート参加も可とする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "データ移行は第1フェーズでマスタ系を先行移行し、トランザクション系は後フェーズに回して旧システムを参照用に残す",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "認証とマスタ配信基盤はサクラ商事との共同利用案を採用する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "ユーザー権限は既存のロール定義を流用し、新規設計は行わない",
      "decided_by": "芦田 巧"
    },
    {
      "id": "D6",
      "content": "障害の一次受け窓口はQAチームにする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D7",
      "content": "移行方式は拠点をグループ分けして順番に切り替える段階移行とする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "本番リリース目標日は2026-10-15に変更する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "移行切替は土曜の深夜帯に実施する",
      "decided_by": "桐生 遥"
    }
  ],
